sql:
SELECT CASE WHEN EXISTS (
    SELECT 1
    FROM songs
    WHERE title = 'Song_Title'
) THEN 'Yes' ELSE 'No' END;

SELECT s.title, l.lyricist
FROM songs s
INNER JOIN lyrics l ON s.song_id = l.song_id;

SELECT song_id
FROM song_matches
WHERE match_type = 'exact';

SELECT s.title, af.danceability, af.energy
FROM songs s
JOIN audio_features af ON s.song_id = af.song_id;
